{"file_text": "@page "/settings"
@using sv_ccca19b012244c0c9d93cadf38361de3.Models
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Sidebar Navigation -->
    <nav class="settings-sidebar">
        <h3 class="sidebar-title">Settings</h3>
        @foreach (var section in _sections)
        {
            <button class="sidebar-item @(section == _activeSection ? "active" : "")"
                    @onclick="() => SetActiveSection(section)">
                <span class="sidebar-icon">@GetSectionIcon(section)</span>
                @section
            </button>
        }
    </nav>

    <!-- Main Content -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">
                <div class="spinner"></div>
                <p>Loading settings…</p>
            </div>
        }
        else
        {
            <!-- Toast Message -->
            @if (_showToast)
            {
                <div class="toast-message @(_toastType)">
                    <span>@_toastMessage</span>
                    <button class="toast-close" @onclick="() => _showToast = false">✕</button>
                </div>
            }

            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfileSection()
                    break;
                case "Notifications":
                    @RenderNotificationsSection()
                    break;
                case "Security":
                    @RenderSecuritySection()
                    break;
                case "Appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

<!-- Revoke Session Confirmation Dialog -->
@if (_showRevokeDialog)
{
    <div class="modal-overlay" @onclick="CancelRevoke">
        <div class="modal-dialog" @onclick:stopPropagation="true">
            <h4>Revoke Session</h4>
            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong> from <strong>@_sessionToRevoke?.Location</strong>?</p>
            <p class="modal-warning">This will immediately sign out that device.</p>
            <div class="modal-actions">
                <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke Session</button>
            </div>
        </div>
    </div>
}

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast
    private bool _showToast;
    private string _toastMessage = "";
    private string _toastType = "success";
    private CancellationTokenSource? _toastCts;

    // Profile
    private UserProfile? _savedProfile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    // Notifications
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    // Security
    private SecuritySettings? _security;
    private bool _showPasswordPanel;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _twoFactorEnabled;
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    // Appearance
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese"];

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        var profile = profileTask.Result;
        _savedProfile = profile;
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;

        var notifs = notifTask.Result;
        _emailNotifications = notifs.EmailNotifications;
        _pushNotifications = notifs.PushNotifications;
        _weeklyDigest = notifs.WeeklyDigest;
        _allChannels = new List<string>(notifs.MutedChannels);
        _mutedChannels = new HashSet<string>(notifs.MutedChannels);

        _security = securityTask.Result;
        _twoFactorEnabled = _security.TwoFactorEnabled;

        var appearance = appearanceTask.Result;
        _theme = appearance.Theme;
        _fontSize = appearance.FontSize;
        _language = appearance.Language;
        _compactMode = appearance.CompactMode;
    }

    private void SetActiveSection(string section) => _activeSection = section;

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    private async Task ShowToast(string message, string type = "success")
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastType = type;
        _showToast = true;
        StateHasChanged();

        try
        {
            await Task.Delay(4000, token);
            _showToast = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ── Profile ──

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section class="settings-section">
            <h2>Profile</h2>
            <p class="section-description">Manage your public profile information.</p>

            <div class="avatar-area">
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">👤</div>
                    }
                </div>
                <div class="avatar-url-display">
                    <label>Avatar URL</label>
                    <input type="url" class="form-control" @bind="_avatarUrl" placeholder="https://example.com/avatar.png" />
                </div>
            </div>

            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" class="form-control" @bind="_displayName" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" class="form-control" @bind="_email" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </section>
    };

    private async Task SaveProfile()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is null) return;
        _displayName = _savedProfile.DisplayName;
        _email = _savedProfile.Email;
        _avatarUrl = _savedProfile.AvatarUrl;
        _bio = _savedProfile.Bio;
    }

    // ── Notifications ──

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section class="settings-section">
            <h2>Notifications</h2>
            <p class="section-description">Choose how you want to be notified.</p>

            <div class="toggle-group">
                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Email Notifications</span>
                        <span class="toggle-desc">Receive notifications via email</span>
                    </div>
                    <label class="switch">
                        <input type="checkbox" @bind="_emailNotifications" />
                        <span class="slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Push Notifications</span>
                        <span class="toggle-desc">Receive push notifications in your browser</span>
                    </div>
                    <label class="switch">
                        <input type="checkbox" @bind="_pushNotifications" />
                        <span class="slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Weekly Digest</span>
                        <span class="toggle-desc">Get a weekly summary of activity</span>
                    </div>
                    <label class="switch">
                        <input type="checkbox" @bind="_weeklyDigest" />
                        <span class="slider"></span>
                    </label>
                </div>
            </div>

            <h3 class="subsection-title">Muted Channels</h3>
            <p class="section-description">Uncheck channels you want to receive notifications from.</p>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    var ch = channel;
                    <label class="channel-item">
                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(ch)"
                               @onchange="e => ToggleMutedChannel(ch, (bool)(e.Value ?? false))" />
                        <span class="channel-name">#@ch</span>
                        <span class="channel-badge @(_mutedChannels.Contains(ch) ? "muted" : "active")">
                            @(_mutedChannels.Contains(ch) ? "Muted" : "Active")
                        </span>
                    </label>
                }
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveNotificationPrefs">Save Preferences</button>
            </div>
        </section>
    };

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task SaveNotificationPrefs()
    {
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    // ── Security ──

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section class="settings-section">
            <h2>Security</h2>
            <p class="section-description">Manage your account security and active sessions.</p>

            <!-- Change Password -->
            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _showPasswordPanel = !_showPasswordPanel">
                    <span>🔑 Change Password</span>
                    <span class="expand-icon">@(_showPasswordPanel ? "▲" : "▼")</span>
                </button>
                @if (_showPasswordPanel)
                {
                    <div class="panel-body">
                        @if (!string.IsNullOrEmpty(_passwordError))
                        {
                            <div class="error-message">@_passwordError</div>
                        }
                        <div class="form-group">
                            <label for="currentPwd">Current Password</label>
                            <input id="currentPwd" type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label for="newPwd">New Password</label>
                            <input id="newPwd" type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label for="confirmPwd">Confirm Password</label>
                            <input id="confirmPwd" type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-primary" @onclick="ChangePassword">Update Password</button>
                        @if (_security?.LastPasswordChange is not null)
                        {
                            <p class="last-changed">Last changed: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
                        }
                    </div>
                }
            </div>

            <!-- Two-Factor Authentication -->
            <div class="toggle-group" style="margin-top: 1.5rem;">
                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Two-Factor Authentication</span>
                        <span class="toggle-desc">Add an extra layer of security to your account</span>
                    </div>
                    <div class="twofa-status">
                        <span class="status-indicator @(_twoFactorEnabled ? "enabled" : "disabled")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                        <label class="switch">
                            <input type="checkbox" @bind="_twoFactorEnabled" />
                            <span class="slider"></span>
                        </label>
                    </div>
                </div>
            </div>

            <!-- Active Sessions -->
            <h3 class="subsection-title">Active Sessions</h3>
            @if (_security?.Sessions is { Count: > 0 })
            {
                <div class="sessions-table-wrapper">
                    <table class="sessions-table">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var (session, index) in _security.Sessions.Select((s, i) => (s, i)))
                            {
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (index == 0)
                                        {
                                            <span class="current-badge">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (index != 0)
                                        {
                                            <button class="btn btn-sm btn-danger" @onclick="() => RequestRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="no-data">No active sessions found.</p>
            }
        </section>
    };

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private async Task ChangePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _showPasswordPanel = false;
        await ShowToast("Password updated successfully!");
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _showRevokeDialog = false;
        _sessionToRevoke = null;
        await ShowToast("Session revoked.");
    }

    // ── Appearance ──

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section class="settings-section">
            <h2>Appearance</h2>
            <p class="section-description">Customize how the application looks and feels.</p>

            <div class="appearance-grid">
                <div class="appearance-controls">
                    <!-- Theme -->
                    <fieldset class="form-group">
                        <legend>Theme</legend>
                        <div class="radio-group">
                            @foreach (var t in _themes)
                            {
                                var theme = t;
                                <label class="radio-option @(_theme == theme ? "selected" : "")">
                                    <input type="radio" name="theme" value="@theme"
                                           checked="@(_theme == theme)"
                                           @onchange="() => _theme = theme" />
                                    <span class="radio-icon">@GetThemeIcon(theme)</span>
                                    @theme
                                </label>
                            }
                        </div>
                    </fieldset>

                    <!-- Font Size -->
                    <fieldset class="form-group">
                        <legend>Font Size</legend>
                        <div class="radio-group">
                            @foreach (var size in _fontSizes)
                            {
                                var s = size;
                                <label class="radio-option @(_fontSize == s ? "selected" : "")">
                                    <input type="radio" name="fontSize" value="@s"
                                           checked="@(_fontSize == s)"
                                           @onchange="() => _fontSize = s" />
                                    @s
                                </label>
                            }
                        </div>
                    </fieldset>

                    <!-- Language -->
                    <div class="form-group">
                        <label for="language">Language</label>
                        <select id="language" class="form-control" @bind="_language">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>

                    <!-- Compact Mode -->
                    <div class="toggle-group">
                        <div class="toggle-row">
                            <div class="toggle-info">
                                <span class="toggle-label">Compact Mode</span>
                                <span class="toggle-desc">Reduce spacing for a denser layout</span>
                            </div>
                            <label class="switch">
                                <input type="checkbox" @bind="_compactMode" />
                                <span class="slider"></span>
                            </label>
                        </div>
                    </div>
                </div>

                <!-- Live Preview -->
                <div class="preview-area">
                    <h4>Preview</h4>
                    <div class="preview-card @GetPreviewClasses()">
                        <div class="preview-header">
                            <span class="preview-dot red"></span>
                            <span class="preview-dot yellow"></span>
                            <span class="preview-dot green"></span>
                            <span class="preview-title">Sample Window</span>
                        </div>
                        <div class="preview-body">
                            <div class="preview-sidebar-mock">
                                <div class="mock-item active-mock"></div>
                                <div class="mock-item"></div>
                                <div class="mock-item"></div>
                            </div>
                            <div class="preview-content-mock">
                                <div class="mock-heading"></div>
                                <div class="mock-text"></div>
                                <div class="mock-text short"></div>
                                <div class="mock-button"></div>
                            </div>
                        </div>
                    </div>
                    <div class="preview-meta">
                        Theme: <strong>@_theme</strong> ·
                        Font: <strong>@_fontSize</strong> ·
                        Lang: <strong>@_language</strong> ·
                        Compact: <strong>@(_compactMode ? "On" : "Off")</strong>
                    </div>
                </div>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </section>
    };

    private static string GetThemeIcon(string theme) => theme switch
    {
        "Light" => "☀️",
        "Dark" => "🌙",
        "System" => "💻",
        _ => ""
    };

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add($"preview-theme-{_theme.ToLowerInvariant()}");
        classes.Add($"preview-font-{_fontSize.ToLowerInvariant()}");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }
}
