+    gap: 0.3rem;
+    min-height: 80px;
+}
+
+.preview-compact .preview-sidebar-mock {
+    gap: 3px;
+}
+
+.preview-compact .preview-content-mock {
+    gap: 4px;
+}
+
+/* ── Responsive ── */
+@media (max-width: 768px) {
+    .settings-layout {
+        flex-direction: column;
+    }
+
+    .settings-sidebar {
+        width: 100%;
+        min-width: unset;
+        flex-direction: row;
+        flex-wrap: wrap;
+        padding: 0.75rem;
+        border-right: none;
+        border-bottom: 1px solid #dee2e6;
+    }
+
+    .sidebar-title {
+        display: none;
+    }
+
+    .sidebar-item {
+        flex: 1;
+        justify-content: center;
+        padding: 0.5rem;
+        border-radius: 6px;
+        min-width: fit-content;
+    }
+
+    .settings-content {
+        padding: 1.5rem 1rem;
+    }
+
+    .appearance-grid {
+        grid-template-columns: 1fr;
+    }
+
+    .avatar-area {
+        flex-direction: column;
+        align-items: center;
+    }
+}
